use warehouse compute_small;

create database bench3;
create schema bench3.seed1;

create table bench3.seed1.customers (id INT, name STRING, email STRING, city STRING, birthday DATE);
create table bench3.seed1.products (id INT, name STRING, category STRING, price_cents INT);
create table bench3.seed1.orders (id INT, customer_id INT, product_id INT, quantity INT, note STRING, ordered_at TIMESTAMP);
create table bench3.seed1.payments (id INT, order_id INT, customer_id INT, method STRING, status STRING, amount_cents INT);
create table bench3.seed1.shipments (id INT, order_id INT, carrier STRING, status STRING, tracking_code STRING);

-- generated rows per table: 1000
-- generated rows orders/payments/shipments: 2000
-- insert batch size: 250
-- deterministic seed: 42






select * from bench3.seed1.customers order by id limit 5;
select * from bench3.seed1.products order by id limit 5;
select * from bench3.seed1.orders order by id limit 5;
select * from bench3.seed1.payments order by id limit 5;
select * from bench3.seed1.shipments order by id limit 5;

-- benchmark join sample 1: customer x order x product x payment x shipment
select c.city, p.category, pay.method, ship.carrier, count(*) as order_count from bench3.seed1.customers c join bench3.seed1.orders o on c.id = o.customer_id join bench3.seed1.products p on p.id = o.product_id join bench3.seed1.payments pay on pay.order_id = o.id join bench3.seed1.shipments ship on ship.order_id = o.id group by c.city, p.category, pay.method, ship.carrier order by order_count desc limit 20;

-- benchmark join sample 2: age bucket x payment status x shipment status
select case when date_part('year', age(cast(current_date as timestamp), cast(c.birthday as timestamp))) < 30 then 'under_30' when date_part('year', age(cast(current_date as timestamp), cast(c.birthday as timestamp))) < 45 then '30_44' when date_part('year', age(cast(current_date as timestamp), cast(c.birthday as timestamp))) < 60 then '45_59' else '60_plus' end as age_bucket, pay.status as payment_status, ship.status as shipment_status, sum(pay.amount_cents) as total_amount_cents from bench3.seed1.customers c join bench3.seed1.orders o on c.id = o.customer_id join bench3.seed1.payments pay on pay.order_id = o.id join bench3.seed1.shipments ship on ship.order_id = o.id group by age_bucket, pay.status, ship.status order by total_amount_cents desc limit 20;
